output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?university ?universityLabel WHERE {
  ?university wdt:P361 wd:Q49113 .
  ?university wdt:P1014 ?president .
  ?president wdt:P21 wd:Q6581072 .
  OPTIONAL {
    ?university rdfs:label ?universityLabel
    FILTER(lang(?universityLabel) = "en")
  }
}

